-- [ ObfusPro+ ]
local nYHAU = bit32 or bit or error("ObfusPro+: Environment error");
local function CYvPGN(Anonc)
    local RFXiWfoT = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
    local EFryh = string.gsub(Anonc, '[^' .. RFXiWfoT .. ']', '')
    local CpyfCGU = {}
    for cRUC = 1, #EFryh, 4 do
        local lRs, Ctw, pZz, fos = string.byte(EFryh, cRUC, cRUC + 3)
        if not lRs then break end
        local GPnJ = string.find(RFXiWfoT, string.char(lRs)) - 1
        local Indn = string.find(RFXiWfoT, string.char(Ctw)) - 1
        local Loxe = pZz and string.find(RFXiWfoT, string.char(pZz)) - 1 or 0
        local kpSx = fos and string.find(RFXiWfoT, string.char(fos)) - 1 or 0
        local shro = GPnJ * 262144 + Indn * 4096 + Loxe * 64 + kpSx
        local DYXt = nYHAU.band(nYHAU.rshift(shro, 16), 255)
        table.insert(CpyfCGU, string.char(nYHAU.bxor(DYXt, 135)))
        if pZz and string.char(pZz) ~= '=' then
            DYXt = nYHAU.band(nYHAU.rshift(shro, 8), 255)
            table.insert(CpyfCGU, string.char(nYHAU.bxor(DYXt, 135)))
        end
        if fos and string.char(fos) ~= '=' then
            DYXt = nYHAU.band(shro, 255)
            table.insert(CpyfCGU, string.char(nYHAU.bxor(DYXt, 135)))
        end
    end
    return table.concat(CpyfCGU)
end
local zXUATd = math.sin(342);
local NFKSrlGc = [===[]===]
local ECOjcJL = CYvPGN(NFKSrlGc)
local IBpHNc = math.sin(224);
task.spawn(assert(loadstring(ECOjcJL)))
